  function render(el){
    var name = el.getAttribute('icon');
    var icon = icons[name];
    if(!icon) return;
    var width = el.getAttribute('width') || icon.width || 24;
    var height = el.getAttribute('height') || width;
    el.setAttribute('aria-hidden', el.getAttribute('aria-hidden') || 'true');
    el.style.display = el.style.display || 'inline-block';
    el.style.width = width + 'px';
    el.style.height = height + 'px';
    el.style.lineHeight = '1';
    el.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ' + icon.width + ' ' + icon.height + '" width="100%" height="100%" fill="currentColor" aria-hidden="true" focusable="false">' + icon.body + '</svg>';
  }

  if(!customElements.get('iconify-icon')){
    customElements.define('iconify-icon', class extends HTMLElement {
      static get observedAttributes(){ return ['icon', 'width']; }
      connectedCallback(){ render(this); }
      attributeChangedCallback(){ render(this); }
    });
  }
